<?php
if (($_GET["key"] ?? "") !== "fsa-hub-deploy-2026") { die("Acesso negado."); }
header("Content-Type: text/plain; charset=utf-8");
echo "=== Instalando Formularios + Helpdesk + Relatorios ===

";
$dir = rtrim(__DIR__, "/");
$files = array(
  "modules/formularios/index.php" => "",
  "modules/formularios/ver.php" => "",
  "modules/formularios/api.php" => "",
  "modules/helpdesk/index.php" => "",
  "modules/helpdesk/novo.php" => "",
  "modules/helpdesk/ver.php" => "",
  "modules/helpdesk/api.php" => "",
  "modules/relatorios/index.php" => "",
);
foreach ($files as $path => $content) {
  $full = $dir . "/" . $path;
  @mkdir(dirname($full), 0755, true);
  file_put_contents($full, base64_decode($content));
  @chmod($full, 0644);
  @chmod(dirname($full), 0755);
  echo "  OK: $path
";
}
echo "
=== PRONTO! ===
";
echo "Formularios: /conecta/modules/formularios/
";
echo "Helpdesk: /conecta/modules/helpdesk/
";
echo "Relatorios: /conecta/modules/relatorios/
";
